workbox_routing_registerRoute(/^\/(produits|categories)(\/|$)/i, new workbox_strategies_NetworkFirst({ "cacheName":"catalogue-pages","networkTimeoutSeconds":5, plugins: [new workbox_expiration_ExpirationPlugin({ maxEntries: 100, maxAgeSeconds: 86400 })] }), 'GET');




